// ChatService owns session lifecycle, memory assembly, and mode-specific chat execution.
//
// ChatService coordinates the shared chat flow before dispatching to a mode.
//
// Main responsibilities:
// 1. Create or validate the session.
// 2. Assemble runtime instruction and conversation memory.
// 3. Scope retrievers and tools for the current request.
// 4. Dispatch to pipeline, agent, or agentic RAG execution.
// 5. Persist user and assistant messages.
type ChatService struct {
	config          *config.Config
	chatModel       model.ChatModel
	retriever       retriever.Retriever
	reranker        pipeline.Reranker
	pipeline        *pipeline.RAGPipeline
	agent           *react.Agent
	knowledgeTool   *internalTool.KnowledgeTool
	agenticRAG      *pipeline.AgenticRAGPipeline
	mcpTools        []tool.BaseTool
	skillBackend    skill.Backend
	skillMiddleware *adk.AgentMiddleware
	sessionRepo     repository.SessionRepository
	messageRepo     repository.MessageRepository
	sessionCache    cachepkg.SessionCache
}

// NewChatService creates the service and initializes optional skill support.
func NewChatService(cfg *config.Config) (*ChatService, error) {
	svc := &ChatService{
		config:       cfg,
		sessionCache: cachepkg.NewNoopSessionCache(),
	}

	if cfg.Agent.EnableSkills {
		backend, err := skill.NewLocalBackend(&skill.LocalBackendConfig{
			BaseDir: cfg.Agent.SkillsDir,
		})
		if err != nil {
			return nil, fmt.Errorf("init skill backend: %w", err)
		}
		mw, err := skill.New(context.Background(), &skill.Config{
			Backend:    backend,
			UseChinese: true,
		})
		if err != nil {
			return nil, fmt.Errorf("init skill middleware: %w", err)
		}
		svc.skillBackend = backend
		svc.skillMiddleware = &mw
	}

	return svc, nil
}

// SetSessionCache overrides the session cache used by ChatService.
func (s *ChatService) SetSessionCache(sessionCache cachepkg.SessionCache) {
	if sessionCache == nil {
		s.sessionCache = cachepkg.NewNoopSessionCache()
		return
	}
	s.sessionCache = sessionCache
}

// SetMCPTools replaces the MCP tool set used for request-scoped agent execution.
func (s *ChatService) SetMCPTools(tools []tool.BaseTool) {
	s.mcpTools = tools
}

