func (s *ChatService) buildSourcesFromDocuments(docs []*schema.Document, maxN int) []Source {
	if len(docs) == 0 || maxN <= 0 {
		return nil
	}

	sources := make([]Source, 0, min(len(docs), maxN))
	for _, doc := range docs {
		if doc == nil || strings.TrimSpace(doc.ID) == "" {
			continue
		}
		sources = append(sources, Source{Content: doc.Content, DocID: doc.ID})
		if len(sources) >= maxN {
			break
		}
	}
	return sources
}

